import React, { useState, useEffect } from 'react';
import Select from 'react-select';
import './AddPurchase.css';

const AddOutflow = ({ handleAdd, locations, materials, employees, projects, outflows, setOutflows }) => {
  const initialOutflowState = {
    location: '',
    materialid: '',
    materialname: '',
    quantity: '',
    width: null,
    lotnumber: '',
    employee: '',
    project: '',
  };

  const [newOutflow, setNewOutflow] = useState(initialOutflowState);
  const [showExtras, setShowExtras] = useState(false);
  const [availableMaterials, setAvailableMaterials] = useState([]);
  const [availableWidths, setAvailableWidths] = useState([]);
  const [availableLots, setAvailableLots] = useState([]);

  useEffect(() => {
    const fetchData = async () => {
      if (newOutflow.location) {
        try {
          const [responseMaterial] = await Promise.all([
            fetch(`http://localhost:8081/PurchasesAPI/materialid/${newOutflow.location}`),
          ]);
  
          const materialList = await responseMaterial.json();
  
          setAvailableMaterials(materialList);
          
        } catch (error) {
          console.error('Error fetching material data:', error);
        }
      }
      if (newOutflow.materialid) {
        try {
          const [responseWidth] = await Promise.all([
            fetch(`http://localhost:8081/PurchasesAPI/widths/${newOutflow.location}/${newOutflow.materialid}`),
          ]);
  
          const materialWidth = await responseWidth.json();
  
          setAvailableWidths(materialWidth);
        } catch (error) {
          console.error('Error fetching material data:', error);
        }
      } else {
        setNewOutflow((prevPurchase) => ({
          ...prevPurchase,
          width: '',
        }));
      }
      if (newOutflow.width) {
        try {
          const [responseLot] = await Promise.all([
            fetch(`http://localhost:8081/PurchasesAPI/lots/${newOutflow.location}/${newOutflow.materialid}/${newOutflow.width}`),
          ]);
  
          const materialLot = await responseLot.json();
  
          setAvailableLots(materialLot);
        } catch (error) {
          console.error('Error fetching material data:', error);
        }
      } else {
        setNewOutflow((prevPurchase) => ({
          ...prevPurchase,
          lotnumber: '',
        }));
      }
    };
  
    fetchData();
  }, [newOutflow.location, newOutflow.materialid, newOutflow.width]);
  console.log('availablemats',availableMaterials);
  

  const handleChange = (e) => {
    const { name, value } = e.target;
    
    if (name === 'location') {
      setNewOutflow(initialOutflowState);
      setNewOutflow((prevOutflow) => ({
        ...prevOutflow,
        [name]: value,
      }));
    } else if (name === 'materialid') {
      const selectedMaterial = materials.find(material => material.matid === value);
      
      if (selectedMaterial) {
        setNewOutflow((prevOutflow) => ({
          ...prevOutflow,
          [name]: value,
          materialname: selectedMaterial.name,
        }));
        
        if (selectedMaterial.extras === 1) {
          setShowExtras(true);
        } else {
          setShowExtras(false);
          setNewOutflow((prevPurchase) => ({
            ...prevPurchase,
            lotnumber: '',
            width: null ,
          }));
          
        }
      }
    } else {
      setNewOutflow((prevOutflow) => ({
        ...prevOutflow,
        [name]: value,
      }));
    }
  };
  
  

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {

      handleAdd(newOutflow);
      setNewOutflow(initialOutflowState);
      setShowExtras(false);
    } catch (error) {
      console.error('Error handling the form submission:', error);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="add-purchase-form">
      <div>
        <label>Location:</label>
        <select name="location" value={newOutflow.location || ''} onChange={handleChange} required>
          <option value="">Select a location</option>
          {locations.map((location) => (
            <option key={location.id} value={location.id}>
              {location.locationname}
            </option>
          ))}
        </select>
      </div>
      {newOutflow.location && (
        <div>
      <div>
        <label>Material ID:</label>
        <Select
  name="materialid"
  value={availableMaterials.find(option => option.value === newOutflow.materialid) || ''}
  onChange={(selectedOption) => handleChange({ target: { name: 'materialid', value: selectedOption.value } })}
  options={availableMaterials.map(material => ({ value: material, label: material }))}
  isSearchable
  required
/>
      </div>
      <div>
        <label>Material Name:</label>
        <input type="text" name="materialname" value={newOutflow.materialname || ''} readOnly required />
      </div>
      </div>
      )}
      {showExtras && newOutflow.materialname &&(
        <div>
          <label>Width:</label>
        <select
          name="width"
          value={newOutflow.width || ''}
          onChange={handleChange}
          required
        >
          <option value="">Select a width</option>
          {availableWidths.map((width) => (
            <option key={width} value={width}>
              {width}
            </option>
          ))}
        </select>
        </div>
      )}
      {showExtras && newOutflow.width && (
        <div>
          <label>Quantity:</label>
          <input type="text" name="quantity" value={newOutflow.quantity || ''} onChange={handleChange} required />
        </div>
      )}
      {showExtras && newOutflow.quantity && (
        <div>
          <label>Lot No:</label>
        <select
          name="lotnumber"
          value={newOutflow.lotnumber || ''}
          onChange={handleChange}
          required
        >
          <option value="">Select a lot #</option>
          {availableLots.map((lot) => (
            <option key={lot} value={lot}>
              {lot}
            </option>
          ))}
        </select>
        </div>
      )}
      
      {!showExtras && newOutflow.materialid && (
        <div>
          <label>Quantity:</label>
          <input type="text" name="quantity" value={newOutflow.quantity || ''} onChange={handleChange} required />
        </div>
      )}
      {newOutflow.quantity && (
      <div>
        <label>Employee:</label>
        <select
          name="employee"
          value={newOutflow.employee || ''}
          onChange={handleChange}
          required
        >
          <option value="">Select an Employee</option>
          {employees.map((employee) => (
            <option key={employee.empid} value={employee.empid}>
              {employee.name}
            </option>
          ))}
        </select>
      </div>
      )}
      {newOutflow.employee && (
      <div>
        <label>Project:</label>
        <select
          name="project"
          value={newOutflow.project || ''}
          onChange={handleChange}
          required
        >
          <option value="">Select a Project</option>
          {projects.map((project) => (
            <option key={project.prid} value={project.prid}>
              {project.name}
            </option>
          ))}
        </select>
      </div>
      )}
      <button type="submit" className="add_purchase_btn">
        Add Outflow
      </button>
    </form>
  );
};

export default AddOutflow;
